import java.util.*;

public class Student implements Comparable<Student> {
    private String studentId;
    public Student(String studentId) { this.studentId = studentId; }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        Student student = (Student) o;
        return Objects.equals(studentId, student.studentId);
    }

    @Override
    public int hashCode() {
        return Objects.hash(studentId);
    }

    @Override
    public int compareTo(Student o) {
        return this.studentId.compareTo(o.studentId);
    }

    public String toString() { return "Student(" + studentId + ")"; }
}

public class StudentManager {
    public static void main(String[] args) {
        Set<Student> students = new HashSet<>();
        students.add(new Student("1002"));
        students.add(new Student("1001"));
        students.add(new Student("1002")); // duplicate

        List<Student> list = new ArrayList<>(students);
        Collections.sort(list);
        for(Student s : list) {
            System.out.println(s);
        }
    }
}
