        for (String s : data) {
            try {
                if (s == null) throw new NullPointerException("Data is null");
                int score = Integer.parseInt(s);
                System.out.println("Parsed: " + score);
            } catch (NumberFormatException e) {
                System.err.println("Invalid number format: " + s);
            } catch (NullPointerException e) {
                System.err.println("Null data encountered");
            } catch (Exception e) {
                System.err.println("Other error");
            } finally {
                System.out.println("解析过程结束");
            }
        }
    }
}
