        ArrayList that = (ArrayList) o;
        return Objects.equals(id, that.id);
    }

    @Override
    public int hashCode() { return Objects.hash(id); }

    @Override
    public int compareTo(ArrayList o) { return this.id.compareTo(o.id); }

    public static void main(String[] args) {
