```java
class Resource {
    private String data;
    private boolean hasData = false;
    public synchronized void produce(String data) throws InterruptedException {
        while (hasData) wait();
        this.data = data;
        System.out.println("生产了: " + data);
        hasData = true;
        notify();
    }
    public synchronized void consume() throws InterruptedException {
        while (!hasData) wait();
        System.out.println("消费了: " + data);
        hasData = false;
        notify();
    }
}
public class ProducerConsumer {
    public static void main(String[] args) {
        Resource res = new Resource();
        new Thread(() -> { try { for (int i=0;i<5;i++) res.produce("物品"+i); } catch (Exception e){} }).start();
        new Thread(() -> { try { for (int i=0;i<5;i++) res.consume(); } catch (Exception e){} }).start();
    }
}
